module.exports = {
  preset: 'ts-jest',
  testEnvironment: 'node',
  testMatch: ['**/tests/**/*.test.ts'],
  moduleFileExtensions: ['ts', 'js', 'json'],
  verbose: true
};

import express from 'express';
import path from 'path';
import fs from 'fs';

export const app = express();

function resolveStaticDir(): string {
  const distPublic = path.join(__dirname, 'public');
  const srcPublic = path.join(process.cwd(), 'src', 'public');
  return fs.existsSync(distPublic) ? distPublic : srcPublic;
}

const staticDir = resolveStaticDir();
app.use(express.static(staticDir));

const PORT = Number(process.env.PORT) || 4445;

export function start(port: number = PORT) {
  const server = app.listen(port, () => {
    console.log(`Server listening on http://localhost:${port}`);
  });
  return server;
}

if (require.main === module) {
  start();
}

